public class Solution {
public boolean solve(String s) {
    int i = 0;
    for (char c : s.toCharArray()) {
        if (c == '(') {
            s = s.substring(0, i) + c + s.substring(i++);
        } else if (c == ')') {
            if (i != 0) {
                s = s.substring(0, i) + c + s.substring(i--);
            }
        } 
    } 
    return i == 0;
}
}

